"use strict";parserFactory.register("tongrenquan.org",()=>new TongrenquanParser);class TongrenquanParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("div.book_list");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector(".read_chapterDetail")}extractTitleImpl(e){return e.querySelector(".infos h1")}extractAuthor(e){let r=e.querySelector(".date span");return r?.textContent??super.extractAuthor(e)}extractLanguage(){return"zh"}findChapterTitle(e){return e.querySelector(".read_chapterName h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book_info")}async fetchChapter(e){let r={makeTextDecoder:()=>new TextDecoder("gbk")};return(await HttpClient.wrapFetch(e,r)).responseXML}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".infos > p")]}}